// // This module implements a 32-bit wide, 2-to-1 demultiplexer. When the selection signal (sel) is 0, the output (out) will reflect the value of input_2; when sel is 1, the output will switch to the value of input_1.
module top_module(sel, input_1, input_2, out);input sel;


	input [31:0] input_1;
	input [31:0] input_2;


	output reg [31:0] out;

	always @(sel, input_1, input_2) begin
		case(sel)
			0: out <= input_1;
			1: out <= input_2;
		endcase
	end
endmodule
